SQL
Copy
CREATE GRAPH WORKSPACE DISTANCEGRAPH
EDGE TABLE DISTANCES
    SOURCE COLUMN HSOURCE
    TARGET COLUMN HTARGET
    KEY COLUMN DKEY
VERTEX TABLE HOTEL
    KEY COLUMN HNO;







